import{_ as i,W as d,X as l,Z as e,$ as a,a0 as c,a1 as n,C as r}from"./framework-a4c02b8f.js";const o={},t=n('<h2 id="_1-基础介绍" tabindex="-1"><a class="header-anchor" href="#_1-基础介绍" aria-hidden="true">#</a> 1 基础介绍</h2><p>Python是当前深度学习领域最为流行的编程语言，它较为现代化，更方便学习和使用。得益于众多开源第三方包的支持，Python具有非常强大的功能。尽管作为一种解释型语言，Python直接编写的代码在性能上和C/C++、Java等语言存在一定的差距，但众多第三方包在底层的计算上依然使用C/C++等进行实现，因此Python的性能依然非常强大。但也由于Python众多的第三方库，对这些数量庞大的库进行管理是一件非常复杂的事情。</p><p>Anaconda提供了对Python包管理的机制，可以创建多个相互隔离的环境空间，每个环境中可以独立的安装各种第三方库。这样的好处是在同时开发多个项目时，不同项目之间的环境配置完全隔离，也避免了不同包之间依赖关系可能导致的潜在问题。</p><h2 id="_2-安装" tabindex="-1"><a class="header-anchor" href="#_2-安装" aria-hidden="true">#</a> 2 安装</h2><h3 id="_2-1-下载安装包" tabindex="-1"><a class="header-anchor" href="#_2-1-下载安装包" aria-hidden="true">#</a> 2.1 下载安装包</h3>',5),u={href:"https://mirrors.tuna.tsinghua.edu.cn/anaconda/archive/?C=M&O=D",target:"_blank",rel:"noopener noreferrer"},h=n(`<p>进入网站后即可看到各个版本的安装包，我们需要根据自己机器的型号，选择合适版本的安装包。这里涉及几个概念：操作系统、计算机系统架构。目前最常见的操作系统就是Windows，而服务器最常用的则是Linux。Linux操作系统有很多不同的发行版本，包括Ubuntu、Centos、Redhats等。我们一般意义上的电脑、服务器均是x86_64架构的，或者具体的说是64位的x86指令集架构。只有一些边缘设备或嵌入式设备才会使用ARM架构，包括树莓派、各种形式的开发板等等。这些设备一般也只会安装Linux操作系统，Linux系统下使用<code>uname -a</code>可以查看机器的操作系统和指令集信息。</p><p>了解以上的概念后，就可以根据自己使用机器的操作系统、系统架构来选择对应的Anaconda安装包。在安装包版本的选择上，本人的习惯是选择最新的，但这也可能会导致对老代码支持的问题。如果遇到这类问题，就需要自己安装不同版本的Anaconda进行尝试了。</p><p>下面是我选择的安装包</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 下载 Linux 安装脚本</span>
<span class="token function">wget</span> https://mirrors.tuna.tsinghua.edu.cn/anaconda/archive/Anaconda3-2023.03-Linux-x86_64.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-进行安装" tabindex="-1"><a class="header-anchor" href="#_2-2-进行安装" aria-hidden="true">#</a> 2.2 进行安装</h3><ul><li>运行安装脚本</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">bash</span> Anaconda3-2023.03-Linux-x86_64.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>按照提示进行安装，一般无脑Enter就行。</li></ul><h3 id="_2-3-配置环境变量" tabindex="-1"><a class="header-anchor" href="#_2-3-配置环境变量" aria-hidden="true">#</a> 2.3 配置环境变量</h3><ul><li>编辑<code>/home/wangxinzhe/.bashrc</code>文件，增加一下内容</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">PATH</span></span><span class="token operator">=</span><span class="token string">&quot;/home/wangxinzhe/anaconda/bin/:<span class="token environment constant">$PATH</span>&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>输入一下命令刷新环境变量</li></ul><div class="language-baseh line-numbers-mode" data-ext="baseh"><pre class="language-baseh"><code>source /home/wangxinzhe/.bashrc
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>以上的一些路径需要根据自己路径进行灵活调整。</p><h3 id="_2-4-验证安装是否成功" tabindex="-1"><a class="header-anchor" href="#_2-4-验证安装是否成功" aria-hidden="true">#</a> 2.4 验证安装是否成功</h3><ul><li><p>在命令台输入<code>conda -V</code>，如果输出了版本信息，则conda安装成功</p></li><li><p>在命令台输入<code>python</code>，如果进入了python环境，则python可以正确使用</p></li></ul><p>如果在输入以上命令后输出了“未找到命令”、“Command not found”等，问题很可能出现在环境变量配置步骤。请查阅其它相关资料并尝试解决。</p><h2 id="_3-使用" tabindex="-1"><a class="header-anchor" href="#_3-使用" aria-hidden="true">#</a> 3 使用</h2><p>安装完成后，就可以正常的使用啦！</p><p>正常的使用和Python没有任何的区别。这里主要介绍使用conda进行python环境管理、包管理的相关概念和常用的命令。</p><h3 id="_3-1-虚拟环境管理" tabindex="-1"><a class="header-anchor" href="#_3-1-虚拟环境管理" aria-hidden="true">#</a> 3.1 虚拟环境管理</h3><ul><li>查看当前虚拟环境列表：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>conda <span class="token function">env</span> list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>创建虚拟环境：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 创建名为 new-env 的虚拟环境，指定Python版本为3.9.5</span>
conda create <span class="token parameter variable">-n</span> new-env <span class="token assign-left variable">python</span><span class="token operator">=</span><span class="token number">3.9</span>.5
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>删除虚拟环境：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 删除 new-env 及下属所有的包</span>
conda remove <span class="token parameter variable">-n</span> new-env <span class="token parameter variable">--all</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>切换虚拟环境：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 激活虚拟环境 new-env</span>
conda activate new-env
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>退出虚拟环境：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 退出当前虚拟环境</span>
conda deactivate
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-环境包管理" tabindex="-1"><a class="header-anchor" href="#_3-2-环境包管理" aria-hidden="true">#</a> 3.2 环境包管理</h3><p>这里的包，就是当前环境下已安装的Python库</p><ul><li>查看当前环境已安装的包</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>conda list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>安装 newpkg 包</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 使用conda （建议）</span>
conda <span class="token function">install</span> newpkg

<span class="token comment"># 使用pip</span>
pip <span class="token function">install</span> newpkg
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>卸载 newpkg 包</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 使用conda （建议）</span>
conda remove newpkg

<span class="token comment"># 使用pip</span>
pip uninstall newpkg
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用pip安装的包，一般也仅会安装到当前环境下。但为了避免不必要的问题，还是推荐使用conda来进行包的安装。</p>`,40);function p(v,m){const s=r("ExternalLinkIcon");return d(),l("div",null,[t,e("p",null,[a("为了加速包的下载，个人推荐从"),e("a",u,[a("清华源（链接点我）"),c(s)]),a("下载安装包。")]),h])}const g=i(o,[["render",p],["__file","1.python.html.vue"]]);export{g as default};
